(window.webpackJsonp=window.webpackJsonp||[]).push([[420],{1047:function(n,r){n.exports='\x3c!-- \r\ntitle: 20-JS入门\r\nsort: \r\n--\x3e \r\n# JavaScript入门\r\n\r\n## 用途\r\n\r\n```javascript\r\n// 写入html\r\ndocument.write("<h1>这是一个标题</h1>");\r\ndocument.write("<p>这是一个段落。</p>");\r\n\r\n// 处理事件\r\n<button type="button" onclick="alert(\'欢迎!\')">点我!</button>\r\n\r\n// 修改html\r\n<p id="demo">\r\nJavaScript 能改变 HTML 元素的内容。\r\n</p>\r\nx=document.getElementById("demo");  //查找元素\r\nx.innerHTML="Hello JavaScript";    //改变内容\r\nx.style.color="#ff0000";           //改变样式\r\n\r\n// 点亮灯泡\r\n<script>\r\nfunction changeImage()\r\n{\r\n    element=document.getElementById(\'myimage\')\r\n    // s.src = s.src.match(\'bulboff\')?"/images/pic_bulbon.gif":"/images/pic_bulboff.gif";\r\n    if (element.src.match("bulbon"))\r\n    {\r\n        element.src="/images/pic_bulboff.gif";\r\n    }\r\n    else\r\n    {\r\n        element.src="/images/pic_bulbon.gif";\r\n    }\r\n}\r\n<\/script>\r\n<img id="myimage" onclick="changeImage()" src="/images/pic_bulboff.gif" width="100" height="180">\r\n    \r\n// 验证输入\r\n<p>请输入数字。如果输入值不是数字，浏览器会弹出提示框。</p>\r\n<input id="demo" type="text">\r\n<script>\r\nfunction myFunction()\r\n{\r\n\tvar x=document.getElementById("demo").value;\r\n\tif(x==""||isNaN(x))\r\n\t{\r\n\t\talert("不是数字");\r\n\t}\r\n}\r\n<\/script>\r\n<button type="button" onclick="myFunction()">点击这里</button>\r\n```\r\n\r\n## 使用\r\n\r\n> 在标签中使用`onclick="Func_name()"`\r\n>\r\n> 调用外部`<script src="Script.js"><\/script>`\r\n\r\n```javascript\r\n<script>\r\nalert("我的第一个 JavaScript");\r\n<\/script>\r\n```\r\n\r\n## 显示数据\r\n\r\n- 使用 **window.alert()** 弹出警告框。\r\n- 使用 **document.write()** 方法将内容写到 HTML 文档中。\r\n- 使用 **innerHTML** 写入到 HTML 元素。\r\n- 使用 **console.log()** 写入到浏览器的控制台。\r\n\r\n```javascript\r\n// document.write()\r\n<button onclick="myFunction()">点我</button>\r\n<script>\r\nfunction myFunction() {\r\n    document.write(Date());\r\n}\r\n<\/script>\r\n\r\n// innerHTML\r\n<p id="demo">我的第一个段落</p>\r\n<script>\r\ndocument.getElementById("demo").innerHTML = "段落已修改。";\r\n<\/script>\r\n\r\n// 写到控制台\r\n<script>\r\na = 5;\r\nb = 6;\r\nc = a + b;\r\nconsole.log(c);\r\n<\/script>\r\n```\r\n\r\n'}}]);